-- ============================================
-- FASE 3: CREAR TABLA DE LOGS Y CONVERSACIONES
-- ============================================
-- Ejecutar en Supabase SQL Editor

-- ============================================
-- 1. TABLA: whatsapp_mensajes (Logs de envíos)
-- ============================================\n\nCREATE TABLE IF NOT EXISTS public.whatsapp_mensajes (\n    -- Identificadores\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    usuario_id UUID REFERENCES public.usuarios(id) ON DELETE CASCADE,\n    plantilla_id UUID REFERENCES public.plantillas_whatsapp(id) ON DELETE SET NULL,\n\n    -- Información del mensaje\n    telefono VARCHAR(20) NOT NULL,\n    tipo VARCHAR(50) NOT NULL,  -- 'inscripcion', 'pago', 'clase', etc\n    mensaje_texto TEXT NOT NULL,\n    estado VARCHAR(20) DEFAULT 'enviado',  -- 'enviado', 'fallido', 'leído', 'entregado'\n    message_id VARCHAR(100),  -- ID devuelto por API de WhatsApp\n\n    -- Metadatos (JSON para flexibilidad)\n    metadatos JSONB DEFAULT '{}',  -- {curso_id, mes, monto, lead_id, etc}\n    respuesta_esperada BOOLEAN DEFAULT false,\n    respuesta_recibida TEXT,\n\n    -- Timestamps\n    creado_en TIMESTAMP WITH TIME ZONE DEFAULT now(),\n    actualizado_en TIMESTAMP WITH TIME ZONE DEFAULT now()\n);\n\n-- Índices para queries frecuentes\nCREATE INDEX IF NOT EXISTS idx_whatsapp_mensajes_usuario_id \n    ON public.whatsapp_mensajes(usuario_id);\n\nCREATE INDEX IF NOT EXISTS idx_whatsapp_mensajes_telefono \n    ON public.whatsapp_mensajes(telefono);\n\nCREATE INDEX IF NOT EXISTS idx_whatsapp_mensajes_tipo \n    ON public.whatsapp_mensajes(tipo);\n\nCREATE INDEX IF NOT EXISTS idx_whatsapp_mensajes_estado \n    ON public.whatsapp_mensajes(estado);\n\nCREATE INDEX IF NOT EXISTS idx_whatsapp_mensajes_creado_en \n    ON public.whatsapp_mensajes(creado_en);\n\nCREATE INDEX IF NOT EXISTS idx_whatsapp_mensajes_message_id \n    ON public.whatsapp_mensajes(message_id);\n\n-- Trigger para actualizar actualizado_en\nDROP TRIGGER IF EXISTS update_whatsapp_mensajes_actualizado_en ON public.whatsapp_mensajes;\n\nCREATE TRIGGER update_whatsapp_mensajes_actualizado_en\n    BEFORE UPDATE ON public.whatsapp_mensajes\n    FOR EACH ROW\n    EXECUTE FUNCTION update_timestamp();\n\n-- ============================================\n-- 2. TABLA: whatsapp_conversaciones (Historial de conversaciones)\n-- ============================================\n\nCREATE TABLE IF NOT EXISTS public.whatsapp_conversaciones (\n    -- Identificadores\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    usuario_id UUID REFERENCES public.usuarios(id) ON DELETE CASCADE,\n    lead_id UUID REFERENCES public.leads(id) ON DELETE CASCADE,\n\n    -- Información de contacto\n    telefono VARCHAR(20) NOT NULL UNIQUE,\n    tipo_contacto VARCHAR(50),  -- 'cliente', 'lead', 'estudiante', 'exalumno'\n\n    -- Últimos mensajes\n    ultimo_mensaje_in TEXT,\n    ultimo_mensaje_out TEXT,\n    ultima_interaccion TIMESTAMP WITH TIME ZONE DEFAULT now(),\n\n    -- Estado\n    estado VARCHAR(20) DEFAULT 'activa',  -- 'activa', 'pausada', 'cerrada', 'lead'\n\n    -- Metadatos\n    metadatos JSONB DEFAULT '{}',  -- {ciudad, fuente, interes, etc}\n\n    -- Contadores\n    total_mensajes_in INTEGER DEFAULT 0,\n    total_mensajes_out INTEGER DEFAULT 0,\n\n    -- Timestamps\n    creado_en TIMESTAMP WITH TIME ZONE DEFAULT now(),\n    actualizado_en TIMESTAMP WITH TIME ZONE DEFAULT now()\n);\n\n-- Índices\nCREATE INDEX IF NOT EXISTS idx_whatsapp_conversaciones_usuario_id \n    ON public.whatsapp_conversaciones(usuario_id);\n\nCREATE INDEX IF NOT EXISTS idx_whatsapp_conversaciones_telefono \n    ON public.whatsapp_conversaciones(telefono);\n\nCREATE INDEX IF NOT EXISTS idx_whatsapp_conversaciones_estado \n    ON public.whatsapp_conversaciones(estado);\n\nCREATE INDEX IF NOT EXISTS idx_whatsapp_conversaciones_lead_id \n    ON public.whatsapp_conversaciones(lead_id);\n\n-- Trigger\nDROP TRIGGER IF EXISTS update_whatsapp_conversaciones_actualizado_en ON public.whatsapp_conversaciones;\n\nCREATE TRIGGER update_whatsapp_conversaciones_actualizado_en\n    BEFORE UPDATE ON public.whatsapp_conversaciones\n    FOR EACH ROW\n    EXECUTE FUNCTION update_timestamp();\n\n-- ============================================\n-- 3. ENABLE ROW LEVEL SECURITY\n-- ============================================\n\nALTER TABLE public.whatsapp_mensajes ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.whatsapp_conversaciones ENABLE ROW LEVEL SECURITY;\n\n-- ============================================\n-- 4. POLÍTICAS RLS\n-- ============================================\n\n-- whatsapp_mensajes: Los usuarios pueden ver sus propios mensajes, admin ve todos\nDROP POLICY IF EXISTS \"Usuarios ven sus propios mensajes\" ON public.whatsapp_mensajes;\nCREATE POLICY \"Usuarios ven sus propios mensajes\" ON public.whatsapp_mensajes\n    FOR SELECT\n    USING (\n        auth.uid() = usuario_id \n        OR EXISTS (SELECT 1 FROM public.usuarios WHERE id = auth.uid() AND rol = 'admin')\n    );\n\nDROP POLICY IF EXISTS \"Admin puede insertar mensajes\" ON public.whatsapp_mensajes;\nCREATE POLICY \"Admin puede insertar mensajes\" ON public.whatsapp_mensajes\n    FOR INSERT\n    WITH CHECK (\n        EXISTS (SELECT 1 FROM public.usuarios WHERE id = auth.uid() AND rol = 'admin')\n        OR auth.uid() = usuario_id\n    );\n\nDROP POLICY IF EXISTS \"Admin puede actualizar mensajes\" ON public.whatsapp_mensajes;\nCREATE POLICY \"Admin puede actualizar mensajes\" ON public.whatsapp_mensajes\n    FOR UPDATE\n    USING (\n        EXISTS (SELECT 1 FROM public.usuarios WHERE id = auth.uid() AND rol = 'admin')\n    );\n\n-- whatsapp_conversaciones: Similar\nDROP POLICY IF EXISTS \"Usuarios ven sus conversaciones\" ON public.whatsapp_conversaciones;\nCREATE POLICY \"Usuarios ven sus conversaciones\" ON public.whatsapp_conversaciones\n    FOR SELECT\n    USING (\n        auth.uid() = usuario_id \n        OR EXISTS (SELECT 1 FROM public.usuarios WHERE id = auth.uid() AND rol = 'admin')\n    );\n\nDROP POLICY IF EXISTS \"Admin gestiona conversaciones\" ON public.whatsapp_conversaciones;\nCREATE POLICY \"Admin gestiona conversaciones\" ON public.whatsapp_conversaciones\n    FOR ALL\n    USING (\n        EXISTS (SELECT 1 FROM public.usuarios WHERE id = auth.uid() AND rol = 'admin')\n    )\n    WITH CHECK (\n        EXISTS (SELECT 1 FROM public.usuarios WHERE id = auth.uid() AND rol = 'admin')\n    );\n\n-- ============================================\n-- 5. VISTAS ÚTILES PARA ANÁLISIS\n-- ============================================\n\n-- Vista: Estadísticas diarias\nDROP VIEW IF EXISTS public.vw_whatsapp_stats_diarias CASCADE;\nCREATE VIEW public.vw_whatsapp_stats_diarias AS\nSELECT\n    DATE(creado_en) as fecha,\n    tipo,\n    estado,\n    COUNT(*) as total,\n    COUNT(CASE WHEN estado = 'enviado' THEN 1 END) as enviados,\n    COUNT(CASE WHEN estado = 'fallido' THEN 1 END) as fallidos,\n    COUNT(CASE WHEN estado = 'leído' THEN 1 END) as leidos\nFROM public.whatsapp_mensajes\nGROUP BY DATE(creado_en), tipo, estado\nORDER BY fecha DESC, tipo;\n\n-- Vista: Usuarios más activos en WhatsApp\nDROP VIEW IF EXISTS public.vw_whatsapp_usuarios_activos CASCADE;\nCREATE VIEW public.vw_whatsapp_usuarios_activos AS\nSELECT\n    u.id,\n    u.nombre,\n    u.email,\n    COUNT(wm.id) as total_mensajes,\n    MAX(wm.creado_en) as ultimo_mensaje,\n    COUNT(CASE WHEN wm.estado = 'fallido' THEN 1 END) as mensajes_fallidos\nFROM public.usuarios u\nLEFT JOIN public.whatsapp_mensajes wm ON u.id = wm.usuario_id\nGROUP BY u.id, u.nombre, u.email\nHAVING COUNT(wm.id) > 0\nORDER BY total_mensajes DESC;\n\n-- Vista: Leads más comprometidos\nDROP VIEW IF EXISTS public.vw_whatsapp_leads_activos CASCADE;\nCREATE VIEW public.vw_whatsapp_leads_activos AS\nSELECT\n    wc.lead_id,\n    wc.telefono,\n    wc.total_mensajes_in,\n    wc.total_mensajes_out,\n    wc.ultimo_mensaje_in,\n    wc.ultima_interaccion,\n    wc.metadatos\nFROM public.whatsapp_conversaciones wc\nWHERE wc.estado IN ('activa', 'lead')\nORDER BY wc.total_mensajes_in DESC, wc.ultima_interaccion DESC;\n\n-- ============================================\n-- 6. VERIFICACIÓN\n-- ============================================\n\n-- Ver tablas creadas\nSELECT tablename FROM pg_tables \nWHERE schemaname = 'public' \nAND tablename LIKE 'whatsapp%'\nORDER BY tablename;\n\n-- Ver vistas creadas\nSELECT viewname FROM pg_views \nWHERE schemaname = 'public' \nAND viewname LIKE 'vw_whatsapp%'\nORDER BY viewname;\n\n-- Ver índices\nSELECT indexname FROM pg_indexes \nWHERE schemaname = 'public' \nAND indexname LIKE 'idx_whatsapp%'\nORDER BY indexname;\n"